import io
import re
import pandas as pd
import boto3

try:
    from dotenv import load_dotenv
    load_dotenv('.env')
except Exception:
    pass

source = 'datagov/nyc-independent-budget-office-ibo-agency-expenditures-fy-1980-2018/files/rows.txt'
bucket = 'lakeqa-yc4103-datalake'
df = pd.read_csv(io.BytesIO(boto3.client('s3').get_object(Bucket=bucket, Key=source)['Body'].read()), dtype=str, low_memory=False)

def money_to_float(value):
    if pd.isna(value):
        return None
    text = str(value).replace('$', '').replace(',', '').strip()
    if text in ['', '-']:
        return None
    if text == '- 0':
        return 0.0
    negative = text.startswith('(') and text.endswith(')')
    if negative:
        text = text[1:-1]
    try:
        number = float(text)
    except ValueError:
        return None
    return -number if negative else number

fy_cols = [col for col in df.columns if str(col).strip().startswith('FY')]
current_agency = None
target_row = None
for _, row in df.iterrows():
    label = '' if pd.isna(row.iloc[0]) else str(row.iloc[0]).strip()
    if label and row[fy_cols].isna().all():
        current_agency = label
    elif label == 'TOTAL DEPT.' and current_agency == 'Department of Health and Mental Hygiene':
        target_row = row
        break
records = []
for col in fy_cols:
    year = re.search(r'\d{4}', col).group(0)
    value = money_to_float(target_row[col])
    if value is not None:
        records.append((year, value))
ranked = sorted(records, key=lambda item: (-item[1], item[0]))
answer = '; '.join(year for year, _ in ranked[:10])
